const input = $input.first()?.json || {};
const payload = input.body && typeof input.body === 'object' ? input.body : input;

const normalize = (value, fallback = '') => {
  if (value === null || value === undefined) return fallback;
  return String(value).trim();
};

const numeroProcesso = normalize(payload.numero_processo);
const autor = normalize(payload.autor);
const reu = normalize(payload.reu, 'Nao informado');
const tipoAcao = normalize(payload.tipo_acao);
const fatos = normalize(payload.fatos);
const pedidoAutor = normalize(payload.pedido_autor);
const textoEditado = normalize(payload.texto_editado_ao_vivo);

const errors = [];
if (!numeroProcesso) errors.push('numero_processo obrigatorio');
if (!autor) errors.push('autor obrigatorio');
if (!tipoAcao) errors.push('tipo_acao obrigatorio');
if (!fatos) errors.push('fatos obrigatorio');
if (!pedidoAutor) errors.push('pedido_autor obrigatorio');

const cnjRegex = /^\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4}$/;
if (numeroProcesso && !cnjRegex.test(numeroProcesso)) {
  errors.push('numero_processo fora do padrao CNJ 0001234-56.2026.8.00.0000');
}

const regrasAplicadas = [
  'Validacao de campos obrigatorios',
  'Validacao de numero de processo no padrao CNJ',
  'Normalizacao de dados textuais',
  'Geracao de defesa por IA com guarda de resposta estruturada',
  'Linguagem juridica formal para revisao humana obrigatoria',
];

if (errors.length) {
  return [
    {
      json: {
        status: 'erro_validacao',
        mensagem: 'Falha de validacao no agente de IA do n8n.',
        erros: errors,
        regras_aplicadas: regrasAplicadas,
        recebido_em: new Date().toISOString(),
      },
    },
  ];
}

const OPENAI_API_KEY = normalize(process.env.OPENAI_API_KEY);
const OPENAI_MODEL = normalize(process.env.OPENAI_MODEL, 'gpt-5.3-codex');
const OPENAI_BASE_URL = normalize(process.env.OPENAI_BASE_URL, 'https://api.openai.com/v1').replace(/\/+$/, '');
const OPENAI_MAX_OUTPUT_TOKENS = Math.max(
  600,
  Number.parseInt(process.env.OPENAI_MAX_OUTPUT_TOKENS || '2200', 10) || 2200,
);
const OPENAI_TIMEOUT_MS = Math.max(
  10000,
  Number.parseInt(process.env.OPENAI_TIMEOUT_MS || '35000', 10) || 35000,
);
const OPENAI_TEMPERATURE_RAW = Number.parseFloat(process.env.OPENAI_TEMPERATURE || '0.15');
const OPENAI_TEMPERATURE = Number.isFinite(OPENAI_TEMPERATURE_RAW)
  ? Math.min(Math.max(OPENAI_TEMPERATURE_RAW, 0), 1)
  : 0.15;

const buildFallbackDraft = (reason = 'fallback_local') => {
  const sintese = `Trata-se de contestacao referente ao processo ${numeroProcesso}, proposta por ${autor} em face de ${reu}, no contexto de ${tipoAcao}.`;
  const fundamentos = `Em sintese, os fatos relevantes indicam: ${fatos}. Impugna-se a narrativa inicial e requer-se a improcedencia dos pedidos autorais, com observancia do contraditorio e ampla defesa.`;
  const pedidos = `Requer-se: (i) recebimento da presente contestacao; (ii) improcedencia integral do pedido autoral (${pedidoAutor}); (iii) producao de todos os meios de prova em direito admitidos.`;

  const minutaBase = [
    'I - Sintese da Demanda',
    sintese,
    '',
    'II - Fundamentos de Defesa',
    fundamentos,
    '',
    'III - Pedidos',
    pedidos,
    '',
    textoEditado ? 'IV - Observacoes do Operador\n' + textoEditado : '',
  ]
    .filter(Boolean)
    .join('\n\n');

  return {
    json: {
      status: 'ok',
      mensagem:
        'Contestacao processada em modo fallback local. Configure OPENAI_API_KEY no n8n para ativar IA generativa.',
      numero_processo: numeroProcesso,
      protocolo_n8n: `N8N-${Date.now()}`,
      regras_aplicadas: [...regrasAplicadas, 'Fallback local sem chamada externa'],
      engine_ia: {
        provider: 'fallback_local',
        model: 'deterministico',
        motivo: reason,
      },
      minuta: {
        texto_base: minutaBase,
        secoes: {
          sintese,
          fundamentos,
          pedidos,
        },
        resumo_estrategico:
          'Resposta em fallback local. Revisar e configurar OpenAI no n8n para argumentacao generativa completa.',
        riscos: ['Sem IA ativa: revisar fundamentacao e citacoes manualmente.'],
      },
      contexto: {
        autor,
        reu,
        tipo_acao: tipoAcao,
      },
      recebido_em: new Date().toISOString(),
    },
  };
};

if (!OPENAI_API_KEY) {
  return [buildFallbackDraft('OPENAI_API_KEY_nao_configurada')];
}

const stripMarkdownFences = (value) => {
  const trimmed = normalize(value);
  if (!trimmed.startsWith('```')) return trimmed;

  return trimmed
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
};

const parseModelJson = (value) => {
  const direct = stripMarkdownFences(value);
  return JSON.parse(direct);
};

const systemPrompt = [
  'Voce e um agente juridico especialista em contestacoes civeis no Brasil.',
  'Escreva em portugues formal, com objetividade, sem inventar jurisprudencia ou fatos.',
  'Nao inclua informacoes fora do caso enviado. Nao use markdown.',
  'Retorne SOMENTE JSON valido com as chaves:',
  '{"resumo_estrategico":"...","sintese":"...","fundamentos":"...","pedidos":"...","observacoes":"...","riscos":["..."]}',
  'Cada campo textual deve vir preenchido e riscos deve ter de 1 a 5 itens.',
].join(' ');

const userPrompt = [
  `numero_processo: ${numeroProcesso}`,
  `autor: ${autor}`,
  `reu: ${reu}`,
  `tipo_acao: ${tipoAcao}`,
  `fatos: ${fatos}`,
  `pedido_autor: ${pedidoAutor}`,
  `texto_editado_ao_vivo: ${textoEditado || '(vazio)'}`,
  'Gere uma contestacao inicial estruturada para revisao humana, mantendo consistencia com os dados acima.',
].join('\n');

const requestBody = {
  model: OPENAI_MODEL,
  temperature: OPENAI_TEMPERATURE,
  max_output_tokens: OPENAI_MAX_OUTPUT_TOKENS,
  input: [
    {
      role: 'system',
      content: [{ type: 'input_text', text: systemPrompt }],
    },
    {
      role: 'user',
      content: [{ type: 'input_text', text: userPrompt }],
    },
  ],
};

const controller = new AbortController();
const timeoutHandle = setTimeout(() => controller.abort(), OPENAI_TIMEOUT_MS);

let openaiPayload = {};

try {
  const response = await fetch(`${OPENAI_BASE_URL}/responses`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${OPENAI_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(requestBody),
    signal: controller.signal,
  });

  openaiPayload = await response.json().catch(() => ({}));

  if (!response.ok) {
    const detail =
      normalize(openaiPayload?.error?.message) || `HTTP_${response.status}`;
    throw new Error(`OpenAI API falhou: ${detail}`);
  }
} catch (error) {
  clearTimeout(timeoutHandle);
  const reason = normalize(error?.message, 'erro_openai').slice(0, 140);
  return [buildFallbackDraft(reason)];
}

clearTimeout(timeoutHandle);

const outputParts = [];

if (typeof openaiPayload?.output_text === 'string' && openaiPayload.output_text.trim()) {
  outputParts.push(openaiPayload.output_text);
}

if (Array.isArray(openaiPayload?.output)) {
  for (const block of openaiPayload.output) {
    if (!Array.isArray(block?.content)) continue;
    for (const contentItem of block.content) {
      const candidateText =
        normalize(contentItem?.text) ||
        normalize(contentItem?.output_text) ||
        normalize(contentItem?.input_text);
      if (candidateText) outputParts.push(candidateText);
    }
  }
}

const rawModelText = outputParts.join('\n').trim();
if (!rawModelText) {
  return [buildFallbackDraft('resposta_openai_sem_conteudo')];
}

let modelData = {};

try {
  modelData = parseModelJson(rawModelText);
} catch {
  return [buildFallbackDraft('resposta_openai_nao_json')];
}

const sinteseIa =
  normalize(modelData.sintese) ||
  `Trata-se de contestacao referente ao processo ${numeroProcesso}, proposta por ${autor} em face de ${reu}, no contexto de ${tipoAcao}.`;

const fundamentosIa =
  normalize(modelData.fundamentos) ||
  `Com base nos fatos informados (${fatos}), impugna-se a narrativa autoral e requer-se a improcedencia dos pedidos.`;

const pedidosIa =
  normalize(modelData.pedidos) ||
  `Requer-se o recebimento da presente contestacao e a improcedencia do pedido autoral (${pedidoAutor}).`;

const observacoesIa = normalize(modelData.observacoes);
const resumoEstrategico =
  normalize(modelData.resumo_estrategico) ||
  'Defesa inicial gerada por IA para revisao humana antes do protocolo.';

const riscos = Array.isArray(modelData.riscos)
  ? modelData.riscos.map((item) => normalize(item)).filter(Boolean).slice(0, 5)
  : [];

const minutaBase = [
  'I - Sintese da Demanda',
  sinteseIa,
  '',
  'II - Fundamentos de Defesa',
  fundamentosIa,
  '',
  'III - Pedidos',
  pedidosIa,
  '',
  textoEditado ? 'IV - Observacoes do Operador\n' + textoEditado : '',
  observacoesIa ? 'V - Observacoes do Agente de IA\n' + observacoesIa : '',
  riscos.length ? 'VI - Riscos e Pontos de Atencao\n- ' + riscos.join('\n- ') : '',
]
  .filter(Boolean)
  .join('\n\n');

return [
  {
    json: {
      status: 'ok',
      mensagem: 'Contestacao processada pelo agente de IA (OpenAI).',
      numero_processo: numeroProcesso,
      protocolo_n8n: `N8N-${Date.now()}`,
      regras_aplicadas: regrasAplicadas,
      engine_ia: {
        provider: 'openai',
        model: OPENAI_MODEL,
        endpoint: `${OPENAI_BASE_URL}/responses`,
        temperature: OPENAI_TEMPERATURE,
        max_output_tokens: OPENAI_MAX_OUTPUT_TOKENS,
      },
      minuta: {
        texto_base: minutaBase,
        secoes: {
          sintese: sinteseIa,
          fundamentos: fundamentosIa,
          pedidos: pedidosIa,
        },
        resumo_estrategico: resumoEstrategico,
        riscos,
      },
      contexto: {
        autor,
        reu,
        tipo_acao: tipoAcao,
      },
      recebido_em: new Date().toISOString(),
    },
  },
];
